import { Module, Global } from '@nestjs/common';
import { APP_GUARD, APP_INTERCEPTOR, APP_FILTER } from '@nestjs/core';
import { JwtAuthGuard } from './guards/jwt-auth.guard';
import { RolesGuard } from './guards/roles.guard';
import { LoggingInterceptor } from './interceptors/logging.interceptor';
import { TransformInterceptor } from './interceptors/transform.interceptor';
import { GlobalExceptionFilter } from './filters/global-exception.filter';

@Global() // Rendre le module global (pas besoin de l'importer partout)
@Module({
  providers: [
    // Guards globaux
    { provide: APP_GUARD, useClass: JwtAuthGuard },
    { provide: APP_GUARD, useClass: RolesGuard },
    // Interceptors globaux
    { provide: APP_INTERCEPTOR, useClass: LoggingInterceptor },
    { provide: APP_INTERCEPTOR, useClass: TransformInterceptor },
    // Filter global
    { provide: APP_FILTER, useClass: GlobalExceptionFilter },
  ],
  exports: [], // Les guards/interceptors sont déjà fournis globalement
})
export class CommonModule {}

// Dans app.module.ts
@Module({
  imports: [CommonModule, AuthModule, UsersModule, ProductsModule],
})
export class AppModule {}
```
Le décorateur `@Global()` rend le module disponible dans toute l'application sans avoir à le réimporter dans chaque module.

